VkPhysicalDevice physicalDevice = VK_NULL_HANDLE;
VkFormat format = VK_NULL_HANDLE;
VkImageType type = VK_NULL_HANDLE;
VkImageTiling tiling = VK_NULL_HANDLE;
VkImageUsageFlags usage = 0;
VkImageCreateFlags flags = 0;
VkImageFormatProperties imageFormatProperties = {};
imageFormatProperties.sType = VK_STRUCTURE_TYPE_IMAGE_FORMAT_PROPERTIES;

VkResult result = vkGetPhysicalDeviceImageFormatProperties(
 physicalDevice,
 format,
 type,
 tiling,
 usage,
 flags,
 &imageFormatProperties
);

if (result == VK_SUCCESS) {
 // تمت العملية بنجاح ويمكن متابعة العمل بعد vkGetPhysicalDeviceImageFormatProperties
